solution_code:
#include <random>
#include <iostream>

int count_in_range(std::mt19937& rng, int rolls, int lo, int hi)
{
    std::uniform_int_distribution<int> die{ 1, 6 };
    int count = 0;
    for (int i = 0; i < rolls; ++i)
    {
        int v = die(rng);
        if (v >= lo && v <= hi)
            ++count;
    }
    return count;
}

int main()
{
    int rolls, lo, hi;
    std::cin >> rolls >> lo >> hi;

    std::mt19937 rng{ 42u };
    std::cout << count_in_range(rng, rolls, lo, hi) << '\n';

    return 0;
}
